mapper.select:
SELECT a.*
FROM eb_assess a

	AND a.`deleted_at` IS NULL

		AND a.entid = #{query.entid}


		AND a.test_uid = #{query.testUid}


		AND a.check_uid = #{query.checkUid}


		AND a.planid = #{query.planId}


		AND a.period = #{query.period}


		AND a.status = #{query.status}


		AND a.frame_id = #{query.frameId}


		AND a.is_show = #{query.isShow}


ORDER BY a.id DESC

SELECT COUNT(1)
FROM eb_assess_space
WHERE entid = #{entid}
  AND assessid = #{assessId}
  AND id = #{spaceId}
  AND deleted_at IS NULL

SELECT pu.test_uid
FROM eb_assess_plan_user pu
		 INNER JOIN eb_assess_plan p ON p.id = pu.planid AND p.entid = pu.entid
WHERE p.entid = #{entid}
  AND p.period = #{period}
  AND p.status = 1
  AND pu.test_uid NOT IN (SELECT a.test_uid
						  FROM eb_assess a
						  WHERE a.entid = #{entid}
							AND a.period = #{period}
							AND a.start_time = #{start}
							AND a.end_time = #{end}
							AND a.`delete` IS NULL)
